<template>

    <header
        class="sticky top-0 z-10 flex flex-col md:flex-row md:items-center justify-between border-b bg-surface-white px-3 py-2.5 sm:px-5">
        <Breadcrumbs class="h-7" :items="breadcrumbs" />
    </header>
    <div class="mt-5 mb-10 w-full px-5">
        <h3 class="text-2xl font-bold mb-3">{{ __('Course Calendar') }}</h3>
        <p class="text-ink-gray-7 mb-5">{{ __('Subscribe to this course calendar to stay updated with assignments'
            +
            ' due dates and class schedule.') }}</p>
        <Button variant="solid" @click="subscribeCourseCalendar()" class="mt-5 mb-5">
            <span>
                {{ __('Subscribe to this course calendar') }}
            </span>
        </Button>

        <div class="space-y-4">

            <div v-if="CalendarInstructions.data">
                <p class="text-sm text-ink-gray-6" v-html="CalendarInstructions.data"></p>
            </div>
            <div v-else>
                <div>
                    <h3 class="text-2xl font-bold mt-8 mb-3">{{ __('How to Import the Calendar in the Major Platforms')
                        }}</h3>
                    <h4 class="text-lg font-semibold mt-3">{{ __('Google Calendar') }}</h4>
                    <p class="text-sm text-ink-gray-6">{{ __('Copy the calendar URL and add it to your Google Calendar by'
                        +
                        ' selecting "Other Calendars" > "From URL".') }}</p>
                </div>

                <div>
                    <h4 class="text-lg font-semibold mt-3">{{ __('Outlook Calendar') }}</h4>
                    <p class="text-sm text-ink-gray-6">{{ __('Copy the calendar URL and add it to your Outlook '
                        + 'Calendar by'
                        +
                        ' selecting "Add Calendar" > "Subscribe from Web".') }}</p>
                </div>

                <div>
                    <h4 class="text-lg font-semibold mt-3">{{ __('Apple Calendar') }}</h4>
                    <p class="text-sm text-ink-gray-6">{{ __('Copy the calendar URL and add it to your Apple Calendar by'
                        +
                        ' selecting "File" > "New Calendar Subscription".') }}</p>
                </div>
            </div>
        </div>

        <div v-if="course.data" class="mt-8 border-t pt-6">
            <h3 class="text-2xl font-bold mb-4">{{ __('When & Where') }}</h3>

            <dl class="space-y-3">
                <div v-if="locationLabel" class="flex flex-col sm:flex-row sm:gap-2">
                    <dt class="font-semibold text-ink-gray-8 sm:w-40 shrink-0">{{ __('Location') }}</dt>
                    <dd class="text-ink-gray-7">{{ locationLabel }}</dd>
                </div>

                <div v-if="course.data.days_of_week?.length" class="flex flex-col sm:flex-row sm:gap-2">
                    <dt class="font-semibold text-ink-gray-8 sm:w-40 shrink-0">{{ __('Days of the Week') }}</dt>
                    <dd class="text-ink-gray-7">
                        {{ course.data.days_of_week.join(', ') }}
                        <template v-if="course.data.from_time && course.data.to_time">
                            · {{ formatTime(course.data.from_time) }}–{{ formatTime(course.data.to_time) }}
                        </template>
                    </dd>
                </div>

                <div v-if="course.data.meeting_dates?.length" class="flex flex-col sm:flex-row sm:gap-2">
                    <dt class="font-semibold text-ink-gray-8 sm:w-40 shrink-0">{{ __('Meeting Dates') }}</dt>
                    <dd class="text-ink-gray-7">
                        <ul class="space-y-1">
                            <li v-for="(meeting, idx) in course.data.meeting_dates" :key="idx">
                                {{ formatDate(meeting.cs_meetdate) }}
                                <template v-if="meeting.cs_fromtime && meeting.cs_totime">
                                    · {{ formatTime(meeting.cs_fromtime) }}–{{ formatTime(meeting.cs_totime) }}
                                </template>
                                <span v-if="meeting.online" class="text-ink-gray-5">· {{ __('Online') }}</span>
                                <span v-else-if="meeting.room_label" class="text-ink-gray-5">· {{ meeting.room_label }}</span>
                                <a v-if="meeting.web_meeting" :href="meeting.web_meeting" target="_blank"
                                    rel="noopener noreferrer" class="text-ink-blue-3 hover:underline">
                                    · {{ __('Join Online') }}
                                </a>
                            </li>
                        </ul>
                    </dd>
                </div>
            </dl>
        </div>

    </div>
</template>
<script setup>
import { createResource, Breadcrumbs, Button } from 'frappe-ui'
import { computed, reactive, onMounted, inject, ref, watch } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { updateDocumentTitle, formatTime, formatDate } from '@/utils'

const route = useRoute()
const router = useRouter()
const user = inject('$user')


const props = defineProps({
    courseName: {
        type: String,
        required: true,
    },
})


const CalendarInstructions = createResource({
    url: 'seminary.seminary.calendar.get_calendar_instructions',
    cache: ['instructions'],
    auto: true,
})

const course = createResource({
    url: 'seminary.seminary.utils.get_course_details',
    cache: ['course', props.courseName],
    params: {
        course: props.courseName,
    },
    auto: true,
})


const subscribeCourseCalendar = () => {

    const calendarUrl = `${window.location.origin}/api/method/seminary.seminary.calendar.course_ics?course_schedule=${encodeURIComponent(props.courseName)}&token=${encodeURIComponent(course.data.calendar_token)}`;
    navigator.clipboard.writeText(calendarUrl).then(() => {
        alert(__('Calendar URL copied to clipboard! You can now add it to your calendar application.'));
    }, () => {
        alert(__('Failed to copy calendar URL. Please try again.'));
    });
};

// For downloading the calendar as an .ics file for validation purposes
// <Button variant="solid" @click="downloadCourseCalendar()" class="mt-5 mb-5">
//     <span>
//         {{ __('JUNK BUTTON Download this course calendar') }}
//     </span>
// </Button>
// const downloadCourseCalendar = () => {

//     const calendarUrl = `${window.location.origin}/api/method/seminary.seminary.calendar.course_ics?course_schedule=${encodeURIComponent(props.courseName)}&token=${encodeURIComponent(course.data.calendar_token)}`;
//     window.location.href = calendarUrl;
//     console.log('Downloading Calendar from URL:', calendarUrl);
// };

const locationLabel = computed(() => {
    const loc = course.data?.location
    if (!loc) return ''
    return [loc.campus, loc.building, loc.room].filter(Boolean).join(' › ')
})

const breadcrumbs = computed(() => {
    let items = [{ label: __('Courses'), route: { name: 'Courses' } }]
    items.push({
        label: course?.data?.course,
        route: { name: 'CourseDetail', params: { courseName: props.courseName } },
    })
    items.push({
        label: __('Calendar'),
        route: { name: 'CourseCalendar', params: { courseName: props.courseName } },
    })

    return items
})

const pageMeta = computed(() => {
    return {
        title: course?.data?.title,
        description: __("Course Calendar for the course " + course?.data?.course),
    }
})

updateDocumentTitle(pageMeta)


</script>